sql:
SELECT ticker_symbol
FROM company
WHERE company_id > 1 AND sector = 'Technology';

SELECT MAX(predicted_price) AS highest_predicted_price
FROM price_prediction
WHERE company_id = (SELECT company_id FROM company WHERE company_name = 'Microsoft Corporation');

external_knowledge:
; Latest closing prices refer to the prices at which the stocks closed in their most recent trading sessions; 
; Predicted stock prices are forecasted prices based on market trends and analysis; 
; Confidence intervals represent the reliability or accuracy of these predictions.

sql:
SELECT MIN(predicted_price) AS lowest_predicted_price
FROM price_prediction
WHERE company_id = 1 AND strftime('%Y-%m-%d', created_at) = '2022-01-02';
